import React, { useRef } from "react";
import './TimingComponent.css';
import AnimatedComponent from "../../app/components/AnimatedComponent";

export interface TimingItem {
    time: string;
    image: string;
    title: string;
    subtitle: string;
}

const TimingComponent = (props: { timing: TimingItem }) => {
    const baseObservableRef = useRef<HTMLDivElement>(null);
    const intersectionRatio = 0.8;

    return (
        <div className='timing-row' ref={baseObservableRef}>
            <AnimatedComponent
                className='base-text left'
                text={props.timing.time}
                animationIn='slide-left-in'
                animationOut='slide-left-out'
                intersectionRatio={intersectionRatio} />
            <div className='timing-icon-column'>
                <AnimatedComponent
                    animationIn='opacity-in'
                    animationOut='opacity-out'
                    intersectionRatio={intersectionRatio} >
                    <img className='timing-icon' src={props.timing.image} />
                </AnimatedComponent>
                <AnimatedComponent
                    className="vertical-line"
                    animationIn='scaling'
                    animationOut='opacity-out'
                    intersectionOffset={200}
                    observableRef={baseObservableRef} />
            </div>
            <div className='timing-right-block'>
                <AnimatedComponent
                    className='base-text right'
                    text={props.timing.title}
                    animationIn='slide-right-in'
                    animationOut='slide-right-out'
                    intersectionRatio={intersectionRatio} />
                <AnimatedComponent
                    className='base-text subtitle'
                    text={props.timing.subtitle}
                    animationIn='slide-right-in'
                    animationOut='slide-right-out'
                    intersectionRatio={intersectionRatio} />
            </div>
        </div>);
}

export default TimingComponent;