import i18n from "i18next";
import { initReactI18next } from "react-i18next";

i18n.use(initReactI18next).init({
    resources: {
        en: {
            translations: {
                days_one: "Day",
                days_other: "Days"
            }
        },
        ru: {
            translations: {
                days_one: "День",
                days_few: "Дня",
                days_many: "Дней",
                hours_one: "Час",
                hours_few: "Часа",
                hours_many: "Часов",
                minutes_one: "Минуту",
                minutes_few: "Минуты",
                minutes_many: "Минут",
                seconds_one: "Секунду",
                seconds_few: "Секунды",
                seconds_many: "Секунд",
            }
        },
    },
    fallbackLng: false,
    debug: true,

    ns: ["translations"],
    defaultNS: "translations",
    lng: "ru",

    keySeparator: false,

    interpolation: {
        escapeValue: false
    }
});

export default i18n;
