import React, { useEffect, useState } from "react";
import './TimerComponent.css'
import { useTranslation } from "react-i18next";
import STRINGS from "../res/strings";
import ProgressIcon from "./ProgressIcon";

const TimerComponent = (props: { date: Date }) => {
    const { t } = useTranslation();
    const [loading, setLoading] = useState(true);
    const targetDate = new Date(
        props.date.getFullYear(),
        props.date.getMonth() - 1,
        props.date.getDate(),
        props.date.getHours());
    var target: number;

    const [days, setDays] = useState(0);
    const [hours, setHours] = useState(0);
    const [minutes, setMinutes] = useState(0);
    const [seconds, setSeconds] = useState(0);

    useEffect(() => {
        target = Date.parse(targetDate.toString());
        updateTime();
        const interval = setInterval(() => updateTime(), 1000);

        return () => clearInterval(interval);
    }, []);

    const updateTime = () => {
        let time = target - Date.now();

        setDays(Math.floor(time / (1000 * 60 * 60 * 24)));
        setHours(Math.floor((time / (1000 * 60 * 60)) % 24));
        setMinutes(Math.floor((time / 1000 / 60) % 60));
        setSeconds(Math.floor((time / 1000) % 60));

        setLoading(false);
    };

    const ProgressItem = (props: { total: number, current: number, title: string }) => {
        return (
            <div className="progress-item">
                <div className="circle">
                    <div className="base-text value">{props.current}</div>
                    <ProgressIcon total={props.total} current={props.current} />
                </div>
                <div className="base-text title">{props.title}</div>
            </div>
        );
    }

    return (
        <div className="timer-block">
            <div className="timer-center-block">
                <div className="timer-title">{STRINGS.TIMER_TITLE}</div>
                {loading ? undefined :
                    <div className="timer-counter-block">
                        <ProgressItem total={365} current={days} title={t("days", { count: days })}/>
                        <ProgressItem total={24} current={hours} title={t("hours", { count: hours })}/>
                        <ProgressItem total={60} current={minutes} title={t("minutes", { count: minutes })}/>
                        <ProgressItem total={60} current={seconds} title={t("seconds", { count: seconds })}/>
                    </div>
                }
            </div>
        </div>
    );
}

export default TimerComponent;